    int minStartingIndex(string s, string pattern) {
        int n = s.size(), m = pattern.size();
        for (int i = 0; i <= n - m; i++) {
            int diff = 0;
            for (int j = 0; j < m; j++) {
                if (s[i + j] != pattern[j]) diff++;
            }
            if (diff <= 1) return i;
        }
        return -1;
    }
};```
